import{_ as d,o as a,c as e,a2 as r}from"./chunks/framework.Cr-Z7ngm.js";const u=JSON.parse('{"title":"入金方式对比总览","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"deposit/methods-overview.md","filePath":"zh-CN/deposit/methods-overview.md"}'),h={name:"deposit/methods-overview.md"};function i(o,t,l,s,n,p){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="入金方式对比总览" tabindex="-1">入金方式对比总览 <a class="header-anchor" href="#入金方式对比总览" aria-label="Permalink to &quot;入金方式对比总览&quot;">​</a></h1><p>香港和新加坡账户的各类入金方式、支持货币、到账时间、手续费及限制说明。</p><h2 id="长桥香港账户" tabindex="-1">长桥香港账户 <a class="header-anchor" href="#长桥香港账户" aria-label="Permalink to &quot;长桥香港账户&quot;">​</a></h2><h3 id="持有香港银行卡" tabindex="-1">持有香港银行卡 <a class="header-anchor" href="#持有香港银行卡" aria-label="Permalink to &quot;持有香港银行卡&quot;">​</a></h3><table tabindex="0"><thead><tr><th>入金方式</th><th>到账时间</th><th>手续费</th></tr></thead><tbody><tr><td><a href="/deposit/银证转账">银证转账</a></td><td>即时</td><td>免费</td></tr><tr><td><a href="/deposit/edda">eDDA</a></td><td>即时</td><td>免费</td></tr><tr><td><a href="/deposit/fps">FPS 转数快</a></td><td>约 2 小时</td><td>免费</td></tr><tr><td><a href="/deposit/网银转账入金">网银转账</a></td><td>1-2 个工作日</td><td>视银行而定</td></tr><tr><td><a href="/deposit/atm-and-counter-cheque">ATM / 柜台 / 支票</a></td><td>1-2 个工作日</td><td>视银行而定</td></tr><tr><td><a href="/deposit/信用卡入金">信用卡入金</a></td><td>—</td><td>见方式说明</td></tr><tr><td><a href="/deposit/电汇入金">电汇</a></td><td>2-5 个工作日</td><td>视银行而定</td></tr></tbody></table><h3 id="非香港银行卡-境外汇款" tabindex="-1">非香港银行卡（境外汇款） <a class="header-anchor" href="#非香港银行卡-境外汇款" aria-label="Permalink to &quot;非香港银行卡（境外汇款）&quot;">​</a></h3><ul><li><a href="/deposit/电汇入金">电汇</a>：通过境外银行电汇转账至长桥香港收款账户</li></ul><h2 id="长桥新加坡账户" tabindex="-1">长桥新加坡账户 <a class="header-anchor" href="#长桥新加坡账户" aria-label="Permalink to &quot;长桥新加坡账户&quot;">​</a></h2><p>新加坡账户支持的入金方式因币种而异，实际以长桥 App 入金页面显示为准。</p><h3 id="sgd-新加坡元" tabindex="-1">SGD（新加坡元） <a class="header-anchor" href="#sgd-新加坡元" aria-label="Permalink to &quot;SGD（新加坡元）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>入金方式</th><th>到账时间</th><th>手续费</th><th>特点</th></tr></thead><tbody><tr><td><a href="/deposit/paynow">PayNow</a></td><td>最快 5 分钟内</td><td>免费</td><td>扫码支付，每次需使用新二维码</td></tr><tr><td><a href="/deposit/dda-authorization">DDA</a></td><td>实时到账</td><td>免费</td><td>一次绑定，支持 5 家新加坡银行</td></tr><tr><td><a href="/deposit/网银与电汇入金">网银转账</a></td><td>1-3 个工作日</td><td>银行可能收费</td><td>支持 FAST、SWIFT 等转账方式</td></tr><tr><td><a href="/deposit/wise">Wise</a></td><td>1-3 个工作日</td><td>银行可能收费</td><td>需上传账户证明</td></tr></tbody></table><p>DDA 支持的银行：DBS/POSB、UOB、OCBC、Maybank、HSBC Singapore。详见 <a href="/deposit/dda-authorization">DDA 自动扣款授权</a>。</p><h3 id="usd-美元" tabindex="-1">USD（美元） <a class="header-anchor" href="#usd-美元" aria-label="Permalink to &quot;USD（美元）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>入金方式</th><th>到账时间</th><th>手续费</th></tr></thead><tbody><tr><td><a href="/deposit/wise">Wise</a></td><td>1-3 个工作日</td><td>银行可能收费</td></tr><tr><td><a href="/deposit/网银与电汇入金">网银转账</a></td><td>1-3 个工作日</td><td>银行可能收费</td></tr></tbody></table><h3 id="hkd-港元" tabindex="-1">HKD（港元） <a class="header-anchor" href="#hkd-港元" aria-label="Permalink to &quot;HKD（港元）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>入金方式</th><th>到账时间</th><th>手续费</th></tr></thead><tbody><tr><td><a href="/deposit/网银与电汇入金">网银转账</a></td><td>1-3 个工作日</td><td>银行可能收费</td></tr></tbody></table><h2 id="入金限制说明" tabindex="-1">入金限制说明 <a class="header-anchor" href="#入金限制说明" aria-label="Permalink to &quot;入金限制说明&quot;">​</a></h2><ul><li>入金账户姓名须与长桥证券账户姓名一致；非本人或联名账户汇款将被拒绝，退款手续费由客户自行承担</li><li>不接受大陆银行卡直接入金，不接受现金存入</li><li>信用卡入金将被拒绝并退回，预计处理约 14 个工作日，退回过程中的银行费用由客户承担</li><li>Wise 入金需上传账户证明（含客户姓名、Wise 账户号码及 Wise logo）</li><li>如有多笔入金汇款，请针对每笔资金分别通知长桥</li><li>因追缴保证金通知而入金时，请及时填写存款通知，避免因不能及时到账导致账户被平仓</li></ul>',18)])])}const c=d(h,[["render",i]]);export{u as __pageData,c as default};
